"use client";
import { useEffect, useState, useMemo, useCallback } from "react";
import { createBrowserClient } from "@supabase/ssr";
import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";

// Import Semua Dashboard Kustom
import DefaultDashboard from "./components/DefaultDashboard";
import RestoDashboard from "./components/RestoDashboard";
import ClinicDashboard from "./components/ClinicDashboard";
import TailorDashboard from "./components/TailorDashboard";
import DemoDashboard from "./components/DemoDashboard";

export default function LeadsPage() {
  const [clientSlug, setClientSlug] = useState("");
  const [loading, setLoading] = useState(true);
  
  // --- STATE UNTUK WARNING & REPORT ---
  const [clientData, setClientData] = useState<any>(null);
  const [usageStats, setUsageStats] = useState({ total: 0, limit: 1000, percentage: 0 });

  const supabase = useMemo(() => createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  ), []);

  const handleLogout = useCallback(async () => {
    console.log("⚠️ Sesi habis karena tidak ada aktivitas. Auto-logout berjalan...");
    await supabase.auth.signOut();
    window.location.href = "/login";
  }, [supabase]);

  useEffect(() => {
    async function getClientContext() {
      setLoading(true);
      try {
        const { data: { user } } = await supabase.auth.getUser();
        
        if (user) {
          const clientId = user.user_metadata?.client_id || user.id;
          
          if (clientId) {
            const { data: clientInfo } = await supabase
              .from("clients")
              .select("id, slug, name, monthly_limit")
              .eq("id", clientId)
              .maybeSingle();
            
            if (clientInfo) {
              setClientSlug(clientInfo.slug);
              setClientData(clientInfo);

              const startOfMonth = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString();
              
              const { count, error } = await supabase
                .from("usage_logs")
                .select("*", { count: "exact", head: true }) 
                .eq("client_id", clientId)
                .gte("created_at", startOfMonth);

              if (error) console.error("Error counting logs:", error);

              const totalChats = count || 0;
              const limit = clientInfo.monthly_limit || 1000;
              const percentage = (totalChats / limit) * 100;

              setUsageStats({ total: totalChats, limit: limit, percentage: percentage });
            }
          }
        }
      } catch (err) {
        console.error("Routing Error:", err);
      } finally {
        setLoading(false);
      }
    }
    getClientContext();
  }, [supabase]);

  useEffect(() => {
    let timeoutId: NodeJS.Timeout;

    const resetTimer = () => {
      clearTimeout(timeoutId);
      const IDLE_TIME_LIMIT = 2 * 60 * 60 * 1000; 
      timeoutId = setTimeout(handleLogout, IDLE_TIME_LIMIT);
    };

    const events = ['mousedown', 'mousemove', 'keypress', 'scroll', 'touchstart'];
    events.forEach(event => document.addEventListener(event, resetTimer));
    resetTimer();

    return () => {
      clearTimeout(timeoutId);
      events.forEach(event => document.removeEventListener(event, resetTimer));
    };
  }, [handleLogout]);

  // ========================================================================
  // 🖨️ FUNGSI DOWNLOAD REPORT (FIX WATERMARK LAYER DI BELAKANG)
  // ========================================================================
  const downloadClientReport = () => {
    if (!clientData) return;
    const doc = new jsPDF();
    const dateStr = new Date().toLocaleString('id-ID', { month: 'long', year: 'numeric' });

    // 1. RENDER WATERMARK PERTAMA KALI (Agar berada di layer paling bawah/belakang)
    doc.setTextColor(240, 244, 248); // Warna abu-abu sangat muda/pudar
    doc.setFontSize(70);
    doc.text("TUMBUH.AI", 105, 150, { angle: 45, align: "center" });

    // 2. RENDER LOGO & HEADER TEKS
    const LOGO_BASE64 = "data:image/png;base64,"; // Isi dengan string base64 logo kamu nanti
    
    if (LOGO_BASE64) {
      doc.addImage(LOGO_BASE64, "PNG", 14, 12, 10, 10); 
      doc.setFontSize(22);
      doc.setTextColor(37, 99, 235);
      doc.text("TUMBUH AI", 28, 20);
    } else {
      doc.setFontSize(22);
      doc.setTextColor(37, 99, 235);
      doc.text("TUMBUH AI", 14, 20);
    }

    doc.setFontSize(10);
    doc.setTextColor(100);
    doc.text("Laporan Pemakaian Sistem Automasi", 14, 26);
    doc.line(14, 30, 196, 30);

    doc.setFontSize(12);
    doc.setTextColor(0); // Teks hitam untuk tabel
    doc.text(`RINGKASAN PEMAKAIAN - ${clientData.name.toUpperCase()}`, 14, 40);
    doc.setFontSize(10);
    doc.text(`Periode Cetak : ${dateStr}`, 14, 47);

    // 3. RENDER TABEL (Akan menutupi area watermark di baliknya dengan rapi)
    autoTable(doc, {
      startY: 55,
      head: [['Metrik Layanan', 'Volume / Status']],
      body: [
        ['Total Percakapan AI Bulan Ini', `${usageStats.total} Interaksi`],
        ['Batas Kuota Bulanan', `${usageStats.limit} Interaksi`],
        ['Sisa Kuota Aman', `${Math.max(0, usageStats.limit - usageStats.total)} Interaksi`],
        ['Persentase Pemakaian', `${usageStats.percentage.toFixed(1)}%`],
        ['Status Tagihan', usageStats.percentage > 100 ? 'OVERLIMIT (Akan Dikenakan Charge Tambahan)' : 'Aman (Dalam Kuota)'],
      ],
      theme: 'grid',
      headStyles: { fillColor: [37, 99, 235] }
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(9);
    doc.setTextColor(150);
    doc.text("Catatan: Chatbot akan tetap membalas pelanggan Anda meskipun kuota habis.", 14, finalY);
    doc.text("Kelebihan kuota (overlimit) akan diakumulasi ke dalam tagihan bulan berikutnya.", 14, finalY + 5);
    doc.text("Laporan ini di-generate otomatis oleh Tumbuh AI System.", 14, finalY + 15);

    doc.save(`TumbuhAI_Report_${clientData.name}_${dateStr}.pdf`);
  };

  if (loading) return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center">
      <div className="w-10 h-10 border-4 border-blue-500/30 border-t-blue-500 rounded-full animate-spin mb-4"></div>
      <div className="font-black italic text-slate-400 uppercase animate-pulse tracking-[0.2em] text-xs">
        Mempersiapkan Workspace...
      </div>
    </div>
  );

  let DashboardComponent = <DefaultDashboard />;
  switch (clientSlug) {
    case "resto-sedap": DashboardComponent = <RestoDashboard />; break;
    case "dokter-gigi": DashboardComponent = <ClinicDashboard />; break;
    case "cherlie-tailor": DashboardComponent = <TailorDashboard />; break;
    case "akun-demo": DashboardComponent = <DemoDashboard />; break;
  }

  // ========================================================================
  // 🎨 LOGIKA TEMA HEADER (FIX DARK MODE MATCHING DENGAN DASHBOARD BAWAHNYA)
  // ========================================================================
  let barTheme = "bg-slate-900/60 border-white/10 shadow-[0_8px_30px_rgb(0,0,0,0.5)]";
  let textTheme = "text-slate-200";
  let badgeTheme = "bg-blue-500/10 text-blue-400 border-blue-500/20";
  let buttonTheme = "bg-blue-600 hover:bg-blue-500 text-white shadow-[0_0_15px_rgba(37,99,235,0.3)]";
  let progressBg = "bg-slate-800";
  let progressFill = "bg-blue-500";
  let alertIcon = "✨";
  let titleText = "Sistem AI Berjalan Optimal";
  let message = `${usageStats.total} dari ${usageStats.limit} interaksi digunakan.`;

  if (usageStats.percentage >= 100) {
    barTheme = "bg-red-950/40 border-red-500/30 shadow-[0_8px_30px_rgba(239,68,68,0.15)]";
    textTheme = "text-red-100";
    badgeTheme = "bg-red-500/20 text-red-400 border-red-500/30 animate-pulse";
    buttonTheme = "bg-red-600 hover:bg-red-500 text-white shadow-[0_0_15px_rgba(239,68,68,0.4)]";
    progressBg = "bg-red-950";
    progressFill = "bg-red-500";
    alertIcon = "🚨";
    titleText = "KUOTA OVERLIMIT";
    message = `Pemakaian telah melampaui batas (${usageStats.total}/${usageStats.limit}). Biaya tambahan berlaku.`;
  } else if (usageStats.percentage >= 80) {
    barTheme = "bg-orange-950/40 border-orange-500/30 shadow-[0_8px_30px_rgba(249,115,22,0.15)]";
    textTheme = "text-orange-100";
    badgeTheme = "bg-orange-500/20 text-orange-400 border-orange-500/30";
    buttonTheme = "bg-orange-500 hover:bg-orange-400 text-white shadow-[0_0_15px_rgba(249,115,22,0.4)]";
    progressBg = "bg-orange-950";
    progressFill = "bg-orange-500";
    alertIcon = "⚠️";
    titleText = "Sisa Kuota Menipis";
    message = `Pemakaian mencapai ${Math.round(usageStats.percentage)}% (${usageStats.total}/${usageStats.limit}).`;
  }

  return (
    // FIX PENTING: bg-[#f8fafc] diganti ke bg-slate-950 agar background utamanya gelap
    <div className="min-h-screen bg-slate-950 font-sans flex flex-col relative">
      
      {/* --- Tumbuh AI Global Top Bar (Dark Glassmorphism Style) --- */}
      <div className="sticky top-0 z-50 p-4 md:p-6 pb-0">
        <div className={`backdrop-blur-xl border rounded-[2rem] px-5 py-4 md:px-8 md:py-5 flex flex-col md:flex-row items-start md:items-center justify-between gap-5 transition-all duration-500 ${barTheme}`}>
          
          <div className="flex items-center gap-4 w-full md:w-auto">
            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-xl md:text-2xl border shrink-0 shadow-inner ${badgeTheme}`}>
              {alertIcon}
            </div>
            
            <div className="flex-1 w-full">
              <div className="flex items-center gap-2 mb-1">
                <p className={`text-[10px] md:text-[11px] font-black uppercase tracking-[0.2em] opacity-70 ${textTheme}`}>
                  Tumbuh AI Monitor
                </p>
                {usageStats.percentage >= 80 && (
                  <span className="relative flex h-2 w-2">
                    <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${progressFill}`}></span>
                    <span className={`relative inline-flex rounded-full h-2 w-2 ${progressFill}`}></span>
                  </span>
                )}
              </div>
              
              <h2 className={`text-sm md:text-base font-bold tracking-tight mb-1 ${textTheme}`}>
                {titleText}
              </h2>
              <p className={`text-xs font-medium opacity-70 ${textTheme}`}>
                {message}
              </p>

              <div className={`w-full h-1.5 md:h-2 rounded-full mt-3 overflow-hidden ${progressBg}`}>
                <div 
                  className={`h-full rounded-full transition-all duration-1000 ease-out ${progressFill}`} 
                  style={{ width: `${Math.min(usageStats.percentage, 100)}%` }}
                ></div>
              </div>
            </div>
          </div>
          
          <button 
            onClick={downloadClientReport}
            className={`w-full md:w-auto px-6 py-3.5 md:py-3 rounded-2xl text-[11px] font-black uppercase tracking-widest transition-all active:scale-95 whitespace-nowrap flex items-center justify-center gap-2 shrink-0 ${buttonTheme}`}
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
            Download Laporan
          </button>
          
        </div>
      </div>

      <div className="flex-1 overflow-auto p-4 md:p-6">
        {DashboardComponent}
      </div>

    </div>
  );
}